when (chunkType) {
    0x5650_3858u -> { // "VP8X" (Extended WebP)
        val w = int24LE(bytes[24], bytes[25], bytes[26]).toInt() + 1
        val h = int24LE(bytes[27], bytes[28], bytes[29]).toInt() + 1
        w to h
    }
    0x5650_3820u -> { // "VP8" (Lossy WebP)
        // Check Sync Code "0x9D 0x01 0x2A"
        if (bytes[23].asInt() != 0x9Du || bytes[24].asInt() != 0x01u || bytes[25].asInt() != 0x2Au) return null
        val w = (int16LE(bytes[26], bytes[27]) and 0x3FFFu).toInt()
        val h = (int16LE(bytes[28], bytes[29]) and 0x3FFFu).toInt()
        w to h
    }
    0x5650_384Cu -> { // "VP8L" (Lossless WebP)
        // Check Lossless
        if (bytes[20].asInt() != 0x2Fu) return null
        val bits = int32LE(bytes[21], bytes[22], bytes[23], bytes[24])
        val w = (bits and 0x3FFFu).toInt() + 1
        val h = ((bits shr 14) and 0x3FFFu).toInt() + 1
        w to h
    }
    else -> null
}

when (filteredBody) {
    is BodyFilterResult.Empty -> {
        logLines.add("--> END ${method.value} (0-byte body)")
    }

    is BodyFilterResult.Skip -> {
        logLines.add(
            buildString {
                append("--> END ${method.value} (")
                filteredBody.reason?.let {
                    append("$it ")
                }
                filteredBody.byteSize?.let {
                    append("$it-byte ")
                }
                append("body omitted)")
            }
        )
    }

    is BodyFilterResult.Content -> {
        logLines.add(filteredBody.read())
        logLines.add("--> END ${method.value} (${filteredBody.byteSize}-byte body)")
    }
}

when {
    length <= 0x7f -> writeByte(length.toByte())
    length <= 0xff -> {
        writeByte(0x81.toByte())
        writeByte(length.toByte())
    }
    length <= 0xffff -> {
        writeByte(0x82.toByte())
        writeByte((length ushr 8).toByte())
        writeByte(length.toByte())
    }
    length <= 0xffffff -> {
        writeByte(0x83.toByte())
        writeByte((length ushr 16).toByte())
        writeByte(((length ushr 8) and 0xff).toByte())
        writeByte(length.toByte())
    }
    else -> {
        writeByte(0x84.toByte())
        writeByte((length ushr 24).toByte())
        writeByte(((length ushr 16) and 0xff).toByte())
        writeByte(((length ushr 8) and 0xff).toByte())
        writeByte(length.toByte())
    }
}

when (algorithm) {
    "RS256" -> Algorithm.RSA256(publicKey as RSAPublicKey, null)
    "RS384" -> Algorithm.RSA384(publicKey as RSAPublicKey, null)
    "RS512" -> Algorithm.RSA512(publicKey as RSAPublicKey, null)
    "ES256" -> Algorithm.ECDSA256(publicKey as ECPublicKey, null)
    "ES384" -> Algorithm.ECDSA384(publicKey as ECPublicKey, null)
    "ES512" -> Algorithm.ECDSA512(publicKey as ECPublicKey, null)
    null -> when (type) {
        "EC" -> {
            val ecKey = publicKey as ECPublicKey
            when (ecKey.params.order.bitLength()) {
                in 249..258 -> Algorithm.ECDSA256(ecKey, null)
                in 379..388 -> Algorithm.ECDSA384(ecKey, null)
                in 518..527 -> Algorithm.ECDSA512(ecKey, null)
                else -> Algorithm.ECDSA256(ecKey, null)
            }
        }
        else -> Algorithm.RSA256(publicKey as RSAPublicKey, null)
    }
    else -> throw IllegalArgumentException("Unsupported algorithm $algorithm")
}
